import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        BookingSystem system = new BookingSystem();
        Movie m = new Movie("M1", "Inception", "Sci-Fi", 148);
        system.addMovie(m);
        Screen sc = new Screen("SC1", "Screen 1");
        sc.setupSeats(3, 0, 0, 4);
        system.addScreen(sc);
        Show show = system.addShow(m, sc, "10:00 AM");
        boolean lk = system.lockSeats(show.getShowId(), Arrays.asList("A1", "A2"), "u1");
        if (!lk) { System.out.println("FAIL_LOCK"); return; }
        Booking b = system.confirmBooking(show.getShowId(), Arrays.asList("A1", "A2"), "u1");
        if (b == null) { System.out.println("FAIL_BOOK"); return; }
        System.out.println("BOOK_OK");
    }
}

