/* Test driver */
import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        BookingSystem system = new BookingSystem();
        Movie m = new Movie("M1", "X", "Y", 100);
        system.addMovie(m);
        Screen sc = new Screen("SC1", "S");
        sc.setupSeats(2, 0, 0, 3);
        system.addScreen(sc);
        Show show = system.addShow(m, sc, "T");
        system.lockSeats(show.getShowId(), Arrays.asList("A1"), "u1");
        Booking b = system.confirmBooking(show.getShowId(), Arrays.asList("A1"), "u1");
        if (b == null) { System.out.println("FAIL_BOOK"); return; }
        if (show.getSeatStatus("A1") != SeatStatus.BOOKED) { System.out.println("FAIL_NOT_BOOKED"); return; }
        boolean cancelled = system.cancelBooking(b.getBookingId());
        if (!cancelled) { System.out.println("FAIL_CANCEL"); return; }
        if (show.getSeatStatus("A1") != SeatStatus.AVAILABLE) { System.out.println("FAIL_NOT_AVAIL"); return; }
        System.out.println("CANCEL_OK");
    }
}

