/* Test driver */
import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        BookingSystem system = new BookingSystem();
        Movie m = new Movie("M1", "X", "Y", 100);
        system.addMovie(m);
        Screen sc = new Screen("SC1", "S");
        sc.setupSeats(2, 0, 1, 2);
        system.addScreen(sc);
        Show show = system.addShow(m, sc, "T");
        system.lockSeats(show.getShowId(), Arrays.asList("A1", "B1"), "u1");
        Booking b = system.confirmBooking(show.getShowId(), Arrays.asList("A1", "B1"), "u1");
        if (b == null) { System.out.println("FAIL"); return; }
        double total = b.getTotalAmount();
        System.out.println(Math.abs(total - 35.0) < 0.01 ? "PRICE_OK" : "PRICE_FAIL");
    }
}
